function cl_fix_fix (	a			: std_logic_vector; 
						a_fmt		: FixFormat_t) 
						return std_logic_vector is
	constant ResultFmt_c 	: FixFormat_t := 
											(
												Signed		=> a_fmt.Signed,
												IntBits		=> a_fmt.IntBits, 
												FracBits	=> 0
											);
begin
	return cl_fix_resize (a, a_fmt, ResultFmt_c, SymZero_s, None_s);
end;

