2354								saturate	: FixSaturate_t	:= Warn_s) 
2355								return std_logic_vector is
2356			constant CarryBit_c : boolean := -- addition performed with an additional integer bit
2357				result_fmt.IntBits > max (a_fmt.IntBits, b_fmt.IntBits) or (saturate = Sat_s or
2358			-- synthesis translate_off
2359				saturate = Warn_s or
2360			-- synthesis translate_on
2361				saturate = SatWarn_s);
2362				-- TODO: CarryBit in cl_fix_resize not needed in all cases
2363			constant TempFmt_c 	: FixFormat_t := 
2364				(
2365					Signed		=> a_fmt.Signed or b_fmt.Signed,
2366					IntBits		=> max (a_fmt.IntBits, b_fmt.IntBits) + toInteger (CarryBit_c), 
2367					FracBits	=> max (a_fmt.FracBits, b_fmt.FracBits)
2368				);
