2374		begin
2375			a_v := cl_fix_resize (a, a_fmt, TempFmt_c, Trunc_s, None_s);
2376			b_v := cl_fix_resize (b, b_fmt, TempFmt_c, Trunc_s, None_s);
2377			temp_v := cl_fix_addsub_internal(a_v, a_fmt, b_v, b_fmt, '1');
