2426		--! cl_fix_addsub implementation	
2427		function cl_fix_addsub (	a			: std_logic_vector; 
2428									a_fmt		: FixFormat_t; 
2429									b			: std_logic_vector; 
2430									b_fmt		: FixFormat_t; 
2431									add			: std_logic;
2432									result_fmt	: FixFormat_t; 
2433									round		: FixRound_t	:= Trunc_s; 
2434									saturate	: FixSaturate_t := Warn_s) 
2435									return std_logic_vector is
2436			variable result_v	: std_logic_vector (cl_fix_width (result_fmt)-1 downto 0);
2437		begin
2438			if to01 (add) = '1' then
2439				result_v := cl_fix_add(a, a_fmt, b, b_fmt, result_fmt, round, saturate);
2440			else
2441				result_v := cl_fix_sub(a, a_fmt, b, b_fmt, result_fmt, round, saturate);

