function max (	a, b 	: integer) 
				return integer is
begin
	if a >= b then
		return a;
	else
		return b;
	end if;
end;

-----------------------------------------------------------------------------------------------	
--! min implementation	
function min (	a, b 	: integer) 
				return integer is
begin
	if a <= b then
		return a;
	else
		return b;
	end if;
end;

-----------------------------------------------------------------------------------------------	
--! to01 implementation	
function to01 (	sl 	: std_logic) 
				return std_logic is
	variable result_v : std_logic;
begin
	if sl = '1' or sl = 'H' then
		result_v := '1';
	else
		result_v := '0';
	end if;
	return result_v;
end;

-----------------------------------------------------------------------------------------------	
--! toInteger implementation
function toInteger (	bool 	: boolean) 
						return integer is
begin
	if bool then
		return 1;
	else
		return 0;
	end if;
end;
